import { lazy, Suspense } from 'react';
import { createBrowserRouter, Navigate } from 'react-router-dom';
import { BlankLayout } from '@/layouts/BlankLayout';
import { MainLayout } from '@/layouts/MainLayout';
import { ProtectedRoute } from './ProtectedRoute';

/**
 * @template {Record<string, unknown>} TModule
 * @param {() => Promise<TModule>} loader
 * @param {keyof TModule} exportName
 * @returns {import('react').LazyExoticComponent<import('react').ComponentType<any>>}
 */
const lazyNamed = (loader, exportName) =>
    lazy(() => loader().then((module) => ({ default: module[exportName] })));

const LoginPage = lazyNamed(() => import('@/features/auth/LoginPage'), 'LoginPage');
const HomePage = lazyNamed(() => import('@/features/home/HomePage'), 'HomePage');
const DomainListPage = lazyNamed(() => import('@/features/domain/DomainListPage'), 'DomainListPage');
const WordListPage = lazyNamed(() => import('@/features/word/WordListPage'), 'WordListPage');
const ForbiddenListPage = lazyNamed(() => import('@/features/forbidden/ForbiddenListPage'), 'ForbiddenListPage');
const UploadPage = lazyNamed(() => import('@/features/import/UploadPage'), 'UploadPage');
const DetailPage = lazyNamed(() => import('@/features/import/DetailPage'), 'DetailPage');

const loadingFallback = <div className='p-6 text-sm text-muted-foreground'>불러오는 중...</div>;

/**
 * @param {import('react').ReactNode} element
 * @returns {JSX.Element}
 */
const withSuspense = (element) => <Suspense fallback={loadingFallback}>{element}</Suspense>;

export const router = createBrowserRouter([
    {
        element: <BlankLayout />,
        children: [{ path: '/login', element: withSuspense(<LoginPage />), handle: { breadcrumb: '로그인' } }],
    },
    {
        element: (
            <ProtectedRoute>
                <MainLayout />
            </ProtectedRoute>
        ),
        children: [
            { index: true, element: <Navigate to="/home" replace /> },
            { path: '/home', element: withSuspense(<HomePage />), handle: { breadcrumb: '홈' } },
            { path: '/domain', element: withSuspense(<DomainListPage />), handle: { breadcrumb: '도메인' } },
            { path: '/word', element: withSuspense(<WordListPage />), handle: { breadcrumb: '단어' } },
            { path: '/forbidden', element: withSuspense(<ForbiddenListPage />), handle: { breadcrumb: '금칙어' } },
            {
                path: '/import',
                element: withSuspense(<UploadPage />),
                handle: { breadcrumb: '데이터 가져오기' },
            },
            {
                path: '/import/:historyId',
                element: withSuspense(<DetailPage />),
                handle: {
                    breadcrumb: ({ params }) =>
                        params.historyId ? `상세 #${params.historyId}` : '상세',
                },
            },
        ],
    },
    {
        path: '*',
        element: <Navigate to="/home" replace />,
    },
]);

