package com.devwogns.trmdict.module.domain.controller;

import com.devwogns.trmdict.common.response.ApiResponse;
import com.devwogns.trmdict.common.response.PageResponse;
import com.devwogns.trmdict.module.domain.dto.DomainSearchDto;
import com.devwogns.trmdict.module.domain.service.DomainService;
import com.devwogns.trmdict.module.domain.vo.DomainDtlVo;
import com.devwogns.trmdict.module.domain.vo.DomainListVo;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@Slf4j
@RestController
@RequestMapping("/api/v1/domains")
@RequiredArgsConstructor
public class DomainController {

    private final DomainService service;

    @PostMapping("/search")
    public ApiResponse<PageResponse<DomainListVo>> search(@RequestBody DomainSearchDto criteria) {
        return ApiResponse.success(service.search(criteria));
    }

    @GetMapping("/{id}")
    public ApiResponse<DomainDtlVo> getById(@PathVariable Long id) {
        return ApiResponse.success(service.findById(id));
    }
}

