package com.devwogns.trmdict.module.importjob.controller;

import com.devwogns.trmdict.common.exception.BusinessException;
import com.devwogns.trmdict.common.exception.ErrorCode;
import com.devwogns.trmdict.common.paging.PageRequest;
import com.devwogns.trmdict.common.response.ApiResponse;
import com.devwogns.trmdict.common.response.PageResponse;
import com.devwogns.trmdict.common.security.AuthPrincipal;
import com.devwogns.trmdict.module.importjob.parser.CsvImportParser;
import com.devwogns.trmdict.module.importjob.parser.ImportType;
import com.devwogns.trmdict.module.importjob.service.ImportJobService;
import com.devwogns.trmdict.module.importjob.vo.ImportErrorVo;
import com.devwogns.trmdict.module.importjob.vo.ImportSummaryVo;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import javax.servlet.http.HttpServletRequest;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.RejectedExecutionException;

/**
 * Import API endpoints.
 *
 * <ul>
 *   <li>POST /api/v1/imports?type=domain|word|term — ADMIN 전용. multipart 업로드 → 202 + historyId.</li>
 *   <li>GET /api/v1/imports/{historyId} — 인증된 사용자 누구나. 작업 요약(ImportSummaryVo).</li>
 *   <li>GET /api/v1/imports/{historyId}/errors — 인증된 사용자 누구나. 행 에러 페이지.</li>
 * </ul>
 */
@RestController
@RequestMapping("/api/v1/imports")
@RequiredArgsConstructor
@Slf4j
public class ImportJobController {

    private final ImportJobService service;
    private final CsvImportParser parser;

    @Value("${import.temp-dir}")
    private String tempDir;

    @PostMapping
    public ResponseEntity<ApiResponse<Map<String, Long>>> upload(
            @RequestParam("type") String typeParam,
            @RequestParam("file") MultipartFile file,
            @AuthenticationPrincipal AuthPrincipal authPrincipal,
            HttpServletRequest req) throws IOException {

        // 1. type 검증 (file 보다 먼저 — 잘못된 type이 빈 파일보다 정보량이 많음)
        ImportType type = ImportType.fromQueryParam(typeParam);
        if (type == null) {
            throw new BusinessException(ErrorCode.IMPORT_3002);
        }

        // 2. file 존재 검증
        if (file == null || file.isEmpty()) {
            throw new BusinessException(ErrorCode.IMPORT_3003);
        }

        // 3. temp 파일 생성 → transferTo → header 검증
        Path tmp = Files.createTempFile(Paths.get(tempDir), "trmdict-import-", ".csv");
        try {
            file.transferTo(tmp);
            parser.validateHeader(tmp, type);

            // AuthPrincipal에서 username 직접 추출. req.getUserPrincipal().getName()은
            // AuthPrincipal이 UserDetails 미구현이라 Object.toString() ('AuthPrincipal@xxx')을
            // 반환해 RQSTR_ID VARCHAR2(50) 컬럼 초과 야기.
            String username = authPrincipal != null ? authPrincipal.getUsername() : "unknown";
            String ip = req.getRemoteAddr();
            long historyId = service.openHistory(type, file.getOriginalFilename(), file.getSize(), username, ip);

            // 4. processAsync 큐 등록 (큐 full → 즉시 RejectedExecutionException)
            try {
                service.processAsync(tmp, historyId, type);
            } catch (RejectedExecutionException ex) {
                service.markRejected(historyId, "Queue full at submit");
                Files.deleteIfExists(tmp);
                throw new BusinessException(ErrorCode.IMPORT_3007);
            }

            Map<String, Long> body = new HashMap<>();
            body.put("historyId", historyId);
            return ResponseEntity.status(HttpStatus.ACCEPTED).body(ApiResponse.success(body));

        } catch (BusinessException ex) {
            Files.deleteIfExists(tmp);
            throw ex;
        } catch (Exception ex) {
            Files.deleteIfExists(tmp);
            log.error("[Import] upload failed", ex);
            throw new BusinessException(ErrorCode.IMPORT_3004);
        }
    }

    @GetMapping("/{historyId}")
    public ApiResponse<ImportSummaryVo> getSummary(@PathVariable long historyId) {
        return ApiResponse.success(service.getSummary(historyId));
    }

    @GetMapping("/{historyId}/errors")
    public ApiResponse<PageResponse<ImportErrorVo>> getErrors(
            @PathVariable long historyId,
            @RequestParam(value = "page", defaultValue = "1") int page,
            @RequestParam(value = "size", defaultValue = "20") int size,
            @RequestParam(value = "sort", required = false) String sort) {
        // sort 파라미터 형식: "column,direction" 예: "row_no,asc" / "error_code,desc"
        String sortColumn = "row_no";
        String sortDirection = "ASC";
        if (sort != null && !sort.trim().isEmpty()) {
            String[] parts = sort.split(",", 2);
            sortColumn = parts[0].trim();
            sortDirection = parts.length > 1 ? parts[1].trim() : "ASC";
        }
        PageRequest pr = PageRequest.of(page, size, sortColumn, sortDirection);
        return ApiResponse.success(service.getErrors(historyId, pr));
    }
}

