package com.devwogns.trmdict.module.auth.controller;

import com.devwogns.trmdict.common.response.ApiResponse;
import com.devwogns.trmdict.common.security.AuthPrincipal;
import com.devwogns.trmdict.common.security.CookieProperties;
import com.devwogns.trmdict.module.auth.dto.LoginDto;
import com.devwogns.trmdict.module.auth.service.AuthService;
import com.devwogns.trmdict.module.auth.vo.AuthUserVo;
import com.fasterxml.jackson.annotation.JsonInclude;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Getter;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.validation.Valid;
import javax.servlet.http.HttpServletResponse;

@Slf4j
@RestController
@RequestMapping("/api/v1/auth")
@RequiredArgsConstructor
public class AuthController {

    private final AuthService authService;
    private final CookieProperties cookieProperties;

    @PostMapping("/login")
    public ApiResponse<LoginResponse> login(@Valid @RequestBody LoginDto dto, HttpServletResponse response) {
        AuthService.LoginResult result = authService.login(dto.getUsername(), dto.getPassword());
        cookieProperties.addAuthCookie(response, result.getAccessToken(), (int) result.getExpiresIn());
        AuthUserVo u = result.getUser();
        return ApiResponse.success(LoginResponse.builder()
                .user(UserSummary.builder()
                        .id(u.getId())
                        .username(u.getUsername())
                        .name(u.getName())
                        .role(u.getRole())
                        .build())
                .build());
    }

    @PostMapping("/logout")
    public ApiResponse<Void> logout(HttpServletResponse response) {
        cookieProperties.clearAuthCookie(response);
        return ApiResponse.success(null);
    }

    @GetMapping("/me")
    public ApiResponse<MeResponse> me(@AuthenticationPrincipal AuthPrincipal principal) {
        AuthUserVo u = authService.getMe(principal.getUserId());
        return ApiResponse.success(MeResponse.builder()
                .id(u.getId())
                .username(u.getUsername())
                .name(u.getName())
                .email(u.getEmail())
                .role(u.getRole())
                .build());
    }

    @Getter
    @Builder
    @AllArgsConstructor
    static class LoginResponse {
        private final UserSummary user;
    }

    @Getter
    @Builder
    @AllArgsConstructor
    static class UserSummary {
        private final Long id;
        private final String username;
        private final String name;
        private final String role;
    }

    @Getter
    @Builder
    @AllArgsConstructor
    @JsonInclude(JsonInclude.Include.ALWAYS)
    static class MeResponse {
        private final Long id;
        private final String username;
        private final String name;
        private final String email;  // null 허용
        private final String role;
    }
