      &lt;SearchForm fields={…} onSearch={handleSearch} /&gt;<br>
      &lt;DataGrid columns={…} pageData={pageData} onRowClick={handleRowClick} /&gt;<br>
      &lt;DetailPanel open={!!selectedId} onClose={() =&gt; setSelectedId(null)}&gt;<br>
      &nbsp;&nbsp;&lt;DetailView fields={dtlFields} data={dtlData} /&gt;<br>
      &lt;/DetailPanel&gt;
    </div>
  </div>
