<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>TrmWordDict2 — 시스템 스펙 현황</title>
<style>
  :root {
    --bg: #0f1117;
    --surface: #1a1d27;
    --surface2: #232635;
    --border: #2e3148;
    --accent: #6c8ef7;
    --accent2: #a78bfa;
    --green: #34d399;
    --yellow: #fbbf24;
    --red: #f87171;
    --orange: #fb923c;
    --text: #e2e8f0;
    --muted: #8892a4;
    --tag-bg: #1e2640;
    --radius: 8px;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: var(--bg); color: var(--text); font-family: 'Segoe UI', system-ui, sans-serif; font-size: 14px; line-height: 1.6; }

  /* ── Layout ── */
  .shell { display: flex; min-height: 100vh; }
  .nav { width: 220px; min-height: 100vh; background: var(--surface); border-right: 1px solid var(--border); padding: 24px 0; position: sticky; top: 0; flex-shrink: 0; }
  .nav-logo { padding: 0 20px 24px; border-bottom: 1px solid var(--border); }
  .nav-logo h1 { font-size: 15px; font-weight: 700; color: var(--accent); }
  .nav-logo span { font-size: 11px; color: var(--muted); }
  .nav-section { padding: 16px 12px 4px; font-size: 10px; font-weight: 700; letter-spacing: .1em; color: var(--muted); text-transform: uppercase; }
  .nav-item { display: block; padding: 7px 20px; font-size: 13px; color: var(--muted); text-decoration: none; border-radius: 0; cursor: pointer; transition: all .15s; border-left: 2px solid transparent; }
  .nav-item:hover, .nav-item.active { color: var(--text); background: var(--surface2); border-left-color: var(--accent); }
  .content { flex: 1; padding: 40px 48px; max-width: 1100px; }

  /* ── Sections ── */
  .section { display: none; }
  .section.visible { display: block; }
  .page-title { font-size: 24px; font-weight: 700; margin-bottom: 6px; }
  .page-subtitle { color: var(--muted); margin-bottom: 32px; font-size: 13px; }

  /* ── Cards ── */
  .card { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 20px 24px; margin-bottom: 16px; }
  .card-title { font-size: 13px; font-weight: 700; color: var(--accent); margin-bottom: 14px; display: flex; align-items: center; gap: 8px; }
  .card-title::before { content: ''; display: inline-block; width: 3px; height: 14px; background: var(--accent); border-radius: 2px; }
  .grid2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
  .grid3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; }

  /* ── Stack Badges ── */
  .stack-row { display: flex; flex-wrap: wrap; gap: 8px; }
  .badge { display: inline-flex; align-items: center; gap: 5px; background: var(--tag-bg); border: 1px solid var(--border); border-radius: 4px; padding: 3px 10px; font-size: 12px; font-weight: 600; }
  .badge.blue { border-color: #3b5bdb33; color: #91abf7; background: #1a2547; }
  .badge.purple { border-color: #6d28d933; color: #c4b5fd; background: #1e1537; }
  .badge.green { border-color: #065f4633; color: #6ee7b7; background: #0d2820; }
  .badge.yellow { border-color: #92400e33; color: #fde68a; background: #231a0a; }
  .badge.orange { border-color: #92400033; color: #fdba74; background: #231509; }
  .badge.gray { border-color: #374151; color: #9ca3af; background: #1a1d27; }

  /* ── Tables ── */
  table { width: 100%; border-collapse: collapse; font-size: 13px; }
  th { text-align: left; padding: 8px 12px; background: var(--surface2); color: var(--muted); font-weight: 600; font-size: 11px; text-transform: uppercase; letter-spacing: .05em; border-bottom: 1px solid var(--border); }
  td { padding: 9px 12px; border-bottom: 1px solid var(--border); vertical-align: top; }
  tr:last-child td { border-bottom: none; }
  tr:hover td { background: var(--surface2); }

  /* ── Method Pills ── */
  .method { display: inline-block; padding: 2px 7px; border-radius: 3px; font-size: 11px; font-weight: 700; min-width: 46px; text-align: center; }
  .method.GET { background: #0d2820; color: #34d399; border: 1px solid #065f46; }
  .method.POST { background: #1a2547; color: #91abf7; border: 1px solid #1e3a8a; }
  .method.PUT { background: #231a0a; color: #fde68a; border: 1px solid #78350f; }
  .method.DELETE { background: #2d0b0b; color: #fca5a5; border: 1px solid #7f1d1d; }

  /* ── Status ── */
  .status-done { color: var(--green); font-size: 12px; }
  .status-wip { color: var(--yellow); font-size: 12px; }
  .status-todo { color: var(--muted); font-size: 12px; }
  .dot { display: inline-block; width: 7px; height: 7px; border-radius: 50%; margin-right: 5px; }
  .dot.green { background: var(--green); }
  .dot.yellow { background: var(--yellow); }
  .dot.gray { background: var(--muted); }

  /* ── Code ── */
  code { font-family: 'Cascadia Code', 'Fira Code', monospace; font-size: 12px; background: #0d1117; padding: 1px 5px; border-radius: 3px; color: #c9d1d9; }
  .code-path { color: var(--accent2); font-family: monospace; font-size: 12px; }

  /* ── Progress ── */
  .progress-bar { background: var(--border); border-radius: 4px; height: 6px; overflow: hidden; margin-top: 6px; }
  .progress-fill { height: 100%; border-radius: 4px; background: linear-gradient(90deg, var(--accent), var(--accent2)); }

  /* ── Cycle row ── */
  .cycle-row { display: flex; align-items: center; gap: 12px; padding: 10px 0; border-bottom: 1px solid var(--border); }
  .cycle-row:last-child { border-bottom: none; }
  .cycle-id { font-size: 11px; font-weight: 700; color: var(--muted); min-width: 60px; }
  .cycle-name { flex: 1; font-size: 13px; }
  .cycle-desc { font-size: 12px; color: var(--muted); flex: 2; }

  /* ── File tree ── */
  .tree { font-family: monospace; font-size: 12px; line-height: 1.9; }
  .tree .dir { color: var(--accent); }
  .tree .file { color: var(--text); }
  .tree .note { color: var(--muted); font-size: 11px; }

