  .progress-bar  { background: var(--border); border-radius: 4px; height: 6px; overflow: hidden; margin-top: 6px; }
  .progress-fill { height: 100%; border-radius: 4px; background: linear-gradient(90deg, var(--accent), var(--accent2)); }

  /* ── Cycle row ── */
  .cycle-row { display: flex; align-items: flex-start; gap: 12px; padding: 10px 0; border-bottom: 1px solid var(--border); }
  .cycle-row:last-child { border-bottom: none; }
  .cycle-id   { font-size: 11px; font-weight: 700; color: var(--muted); min-width: 72px; padding-top: 2px; }
  .cycle-name { flex: 1; font-size: 13px; white-space: nowrap; }
  .cycle-desc { font-size: 12px; color: var(--muted); flex: 2; }

  /* ── File tree ── */
  .tree { font-family: 'Cascadia Code', monospace; font-size: 12px; line-height: 2; }
  .tree .dir  { color: var(--accent); }
  .tree .file { color: var(--text); }
  .tree .note { color: var(--muted); font-size: 11px; }

  /* ── KV list ── */
  .kv { display: grid; grid-template-columns: 160px 1fr; gap: 6px 16px; align-items: start; }
  .kv dt { color: var(--muted); font-size: 12px; padding-top: 2px; }
  .kv dd  { font-size: 13px; }

  /* ── Section divider ── */
  h3.divider { font-size: 11px; font-weight: 700; letter-spacing: .1em; color: var(--muted); text-transform: uppercase; margin: 24px 0 12px; padding-bottom: 6px; border-bottom: 1px solid var(--border); }

  /* ── Error code module tag ── */
  .ec-module { display: inline-block; font-size: 11px; font-weight: 700; padding: 1px 6px; border-radius: 3px; margin-right: 4px; }
  .ec-module.common   { background: #1c1c1c;  color: #9ca3af; }
  .ec-module.auth     { background: #1a2547;  color: #91abf7; }
  .ec-module.import   { background: #231509;  color: #fdba74; }
  .ec-module.domain   { background: #0d2820;  color: #6ee7b7; }
  .ec-module.word     { background: #1e1537;  color: #c4b5fd; }
  .ec-module.forbidden{ background: #2d0b0b;  color: #fca5a5; }

  /* ── Entity field rows ── */
  .field-header { display: grid; grid-template-columns: 200px 200px 1fr; padding: 6px 12px; background: var(--surface2); font-size: 11px; font-weight: 700; color: var(--muted); text-transform: uppercase; }
  .field-row    { display: grid; grid-template-columns: 200px 200px 1fr; padding: 6px 12px; border-bottom: 1px solid var(--border); font-size: 12px; }
  .field-row:last-child { border-bottom: none; }
  .field-java { color: var(--accent2); }
  .field-col  { color: var(--orange); }
  .field-desc { color: var(--muted); }

  .scrollable { max-height: 380px; overflow-y: auto; }
  .scrollable::-webkit-scrollbar { width: 4px; }
  .scrollable::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

  del { color: var(--muted); opacity: .6; }
</style>
