  <div class="page-title">API 엔드포인트</div>
  <div class="page-subtitle">Base: <code>/api/v1</code> · 응답: <code>ApiResponse&lt;T&gt;</code> · 인증: HttpOnly Cookie</div>

  <h3 class="divider">Auth — /api/v1/auth</h3>
  <div class="card" style="padding:0">
    <table>
      <tr><th>Method</th><th>Path</th><th>인증</th><th>Request</th><th>Response</th></tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/auth/login</code></td>
        <td>없음</td>
        <td><code>LoginDto</code><br><small style="color:var(--muted)">username, password</small></td>
        <td>Cookie 발급 + <code>LoginResponse</code><br><small style="color:var(--muted)">user: {id, username, name, role}</small></td>
      </tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/auth/logout</code></td>
        <td>Cookie</td>
        <td>없음</td>
        <td>Cookie 만료 처리</td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/auth/me</code></td>
        <td>Cookie</td>
        <td>없음</td>
        <td><code>MeResponse</code><br><small style="color:var(--muted)">id, username, name, email(nullable), role</small></td>
      </tr>
    </table>
  </div>

  <h3 class="divider">Domain — /api/v1/domains</h3>
  <div class="card" style="padding:0">
    <table>
      <tr><th>Method</th><th>Path</th><th>인증</th><th>Request</th><th>Response</th></tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/domains/search</code></td>
        <td>USER+</td>
        <td><code>DomainSearchDto</code><br><small style="color:var(--muted)">keyword, dataTypeNm, useYn, page, size, sort</small></td>
        <td><code>PageResponse&lt;DomainListVo&gt;</code></td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/domains/{id}</code></td>
        <td>USER+</td>
        <td>PathVariable: id</td>
        <td><code>DomainDtlVo</code> (전 필드 flat)</td>
      </tr>
    </table>
  </div>

  <h3 class="divider">Word — /api/v1/words</h3>
  <div class="card" style="padding:0">
    <table>
      <tr><th>Method</th><th>Path</th><th>인증</th><th>Request</th><th>Response</th></tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/words/search</code></td>
        <td>USER+</td>
        <td><code>WordSearchDto</code><br><small style="color:var(--muted)">keyword, frmWordYn, useYn, page, size, sort</small></td>
        <td><code>PageResponse&lt;WordListVo&gt;</code></td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/words/{id}</code></td>
        <td>USER+</td>
        <td>PathVariable: id</td>
        <td><code>WordDtlVo</code></td>
      </tr>
    </table>
  </div>

  <h3 class="divider">Forbidden — /api/v1/forbiddens</h3>
  <div class="card" style="padding:0">
    <table>
      <tr><th>Method</th><th>Path</th><th>인증</th><th>Request</th><th>Response</th></tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/forbiddens/search</code></td>
        <td>USER+</td>
        <td><code>ForbiddenSearchDto</code></td>
        <td><code>PageResponse&lt;ForbiddenListVo&gt;</code></td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/forbiddens/{id}</code></td>
        <td>USER+</td>
        <td>PathVariable: id</td>
        <td><code>ForbiddenDtlVo</code></td>
      </tr>
    </table>
  </div>

  <h3 class="divider">Import — /api/v1/imports</h3>
  <div class="card" style="padding:0">
    <table>
      <tr><th>Method</th><th>Path</th><th>인증</th><th>Request</th><th>Response</th></tr>
      <tr>
        <td><span class="method POST">POST</span></td>
        <td><code>/imports?type=domain|word|term</code></td>
        <td>ADMIN</td>
        <td>multipart/form-data<br><small style="color:var(--muted)">file (max 50MB) · UTF-8 CSV</small></td>
        <td>202 + <code>{ historyId: Long }</code></td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/imports/{historyId}</code></td>
        <td>USER+</td>
        <td>PathVariable: historyId</td>
        <td><code>ImportSummaryVo</code><br><small style="color:var(--muted)">status, totRowCnt, succRowCnt, failRowCnt…</small></td>
      </tr>
      <tr>
        <td><span class="method GET">GET</span></td>
        <td><code>/imports/{historyId}/errors</code></td>
        <td>USER+</td>
        <td>page, size, sort<br><small style="color:var(--muted)">format: "row_no,asc"</small></td>
        <td><code>PageResponse&lt;ImportErrorVo&gt;</code></td>
      </tr>
    </table>
  </div>

  <div class="card">
    <div class="card-title">공통 응답 포맷</div>
    <div class="grid2">
      <div>
        <div style="font-size:12px;color:var(--green);margin-bottom:6px">성공 (2xx)</div>
        <pre style="background:#0d1117;padding:12px;border-radius:4px;font-size:12px;color:#c9d1d9">{
  "success": true,
  "data": { ... }
}</pre>
      </div>
      <div>
        <div style="font-size:12px;color:var(--red);margin-bottom:6px">에러 (4xx / 5xx)</div>
        <pre style="background:#0d1117;padding:12px;border-radius:4px;font-size:12px;color:#c9d1d9">{
  "success": false,
  "errorCode": "DOMAIN_2001",
  "message": "도메인을 찾을 수 없습니다."
}</pre>
      </div>
    </div>
    <div style="margin-top:14px;font-size:12px;color:var(--muted)">
      페이지 응답: <code>PageResponse&lt;T&gt;</code> — content[], page, size, totalElements, totalPages
    </div>
  </div>
</section>

<!-- ─── BE Entity ─── -->
<section id="be-entity" class="section">
